//! mesh-elect — host-side RAM-aware stage elector for catch-and-release provisioning
//! (resilient mesh component 3; docs/R1_RESILIENT_MESH.md).
//!
//! A node's stage is tied to the shard it holds on disk, so the election happens at
//! SHARD-ASSIGNMENT time (when mass-equip provisions a device), not at every boot. This
//! tool runs on the HOST during `mass-equip.sh`: it pulls a live seed node's membership
//! from `/mesh/peers`, then asks `recommend_stage_from` which stage a NEW device of a
//! given free-RAM capacity should take to best balance the mesh (fill the most
//! under-replicated stage first; bigger nodes take bigger shards).
//!
//! Output: the chosen stage as `A..B` on stdout (consumed by mass-equip).
//! Exit codes: 0 = printed a stage; 2 = usage/arg error; 3 = mesh already fully
//! replicated (caller should fall back to round-robin); 4 = seed unreachable / bad JSON.
//! A non-zero exit always means "fall back" — provisioning never blocks on the elector.
use distributed_inference::mesh_gossip::{recommend_stage_from, PeerInfo};

fn parse_stages(s: &str) -> Vec<(usize, usize)> {
    s.split(',')
        .filter_map(|p| {
            let (a, b) = p.trim().split_once("..")?;
            Some((a.trim().parse().ok()?, b.trim().parse().ok()?))
        })
        .collect()
}

fn main() {
    let mut seed = String::new();
    let mut stages_s = String::new();
    let mut capacity_mb: u64 = 0;
    let mut target: usize = 2;
    let mut model_id: Option<String> = None;
    let mut args = std::env::args().skip(1);
    while let Some(a) = args.next() {
        match a.as_str() {
            "--seed" => seed = args.next().unwrap_or_default(),
            "--stages" => stages_s = args.next().unwrap_or_default(),
            "--capacity-mb" => capacity_mb = args.next().and_then(|v| v.parse().ok()).unwrap_or(0),
            "--target-replicas" => target = args.next().and_then(|v| v.parse().ok()).unwrap_or(2),
            "--model-id" => model_id = args.next(),
            other => {
                eprintln!("mesh-elect: unknown arg {other}");
                std::process::exit(2);
            }
        }
    }
    if seed.is_empty() || stages_s.is_empty() {
        eprintln!(
            "usage: mesh-elect --seed http://ip:port --stages 0..12,12..24 \
             --capacity-mb N [--target-replicas 2] [--model-id ID]"
        );
        std::process::exit(2);
    }
    let stages = parse_stages(&stages_s);

    // Pull the seed's live membership (self + discovered live peers).
    let agent = ureq::AgentBuilder::new()
        .timeout_connect(std::time::Duration::from_secs(3))
        .timeout(std::time::Duration::from_secs(5))
        .build();
    let url = format!("{}/mesh/peers", seed.trim_end_matches('/'));
    let resp = match agent.get(&url).call() {
        Ok(r) => r,
        Err(e) => {
            eprintln!("mesh-elect: seed {url} unreachable: {e}");
            std::process::exit(4);
        }
    };
    let v: serde_json::Value = match resp.into_json() {
        Ok(v) => v,
        Err(e) => {
            eprintln!("mesh-elect: seed {url} bad json: {e}");
            std::process::exit(4);
        }
    };

    let mut peers: Vec<PeerInfo> = Vec::new();
    if let Some(s) = v.get("self") {
        if let Ok(p) = serde_json::from_value::<PeerInfo>(s.clone()) {
            peers.push(p);
        }
    }
    if let Some(arr) = v.get("live_peers").and_then(|x| x.as_array()) {
        for it in arr {
            if let Ok(p) = serde_json::from_value::<PeerInfo>(it.clone()) {
                peers.push(p);
            }
        }
    }
    // Default the model to whatever the seed serves (its self.model_id).
    let model = model_id.unwrap_or_else(|| {
        peers
            .first()
            .map(|p| p.model_id.clone())
            .unwrap_or_default()
    });

    match recommend_stage_from(&peers, &model, &stages, capacity_mb, target) {
        Some((a, b)) => println!("{a}..{b}"),
        None => {
            eprintln!(
                "mesh-elect: every stage already has >= {target} replicas; no new stage needed"
            );
            std::process::exit(3);
        }
    }
}
